Version: Deno 2.6.5

A bug appeared in Deno v2.6.4 that can cause requests made using the `node:https` module to fail with a "socket hang up" error. Deno v2.6.3 and previous versions are unaffected. My gut feeling is that PR #31709 is to blame.

I can reliably reproduce the bug on both Debian 13 and macOS 26 by running the following program. For me it might output "OK" a few times, but always fails within a couple of minutes.

```javascript
import https from "node:https";

function delay_promise(milliseconds, value) {
    return new Promise(function (resolve) {
        setTimeout(resolve, milliseconds, value);
    });
}

function stream_sink(readable) {
    return new Promise(function (resolve, reject) {
        readable.setEncoding("utf8");
        readable.on("data", function () {
            return;
        });
        readable.on("end", resolve);
        readable.on("error", reject);
    });
}

function run_test() {
    const url = "https://ccapp-test.s3.amazonaws.com";
    return new Promise(function (resolve, reject) {
        const head_req = https.request(url, {method: "HEAD"});
        head_req.once("error", reject);
        head_req.once("response", function () {
            const put_req = https.request(url, {method: "PUT"});
            put_req.once("error", reject);
            put_req.once("response", function (response) {
                stream_sink(response).then(resolve).catch(reject);
            });
            put_req.end(new Uint8Array(65536));
        });
        head_req.end();
    });
}

function run_until_fail() {
    return run_test().then(function () {
        console.log("OK, retrying...");
        return delay_promise(1000).then(run_until_fail);
    });
}

run_until_fail().catch(function (error) {
    console.log("FAIL:", error);
});
```

denoland/deno#31896.body:
## Description

While trying to develop a linter plugin to inspect comments I encountered an issue where accessing the `comments` property on a `Program` node would only return the comments of the first file being linted.

The problem did not show up (expectedly) until multiple files are linted.


## Setup to reproduce

Let's consider the following plugin and files `a.js` and `b.js`

```ts
==> scripts/deno-plugins/jsdoc.ts <==
const noAnyInJsdoc: Deno.lint.Rule = {
	create(context) {
		console.log(context);
		// console.log(context.sourceCode.getAllComments())
		return {
			Program(node) {
				console.log(node);
				console.log(node.comments);
			},
		};
	},
};

const plugin: Deno.lint.Plugin = {
	name: "jsdoc-rules",
	rules: { "no-any-in-jsdoc": noAnyInJsdoc },
};

export default plugin;
```

```js
==> a.js <==
export class A {
	/** @type {string} */
	#name;

	/**
	 * @param {any} name
	 */
	constructor(name) {
		this.#name = name;
	}

	get name() {
		return this.#name;
	}
}
```

```js
==> b.js <==
/**
 * @template V
 */
class B {
	/** @type Array<V> */
	#values = [];

	/**
	 * @return Array<V>
	 */
	get values() {
		return this.#values;
	}
}

/**
 * @extends {B<any>}
 */
export default class C extends B {
	/** @type {string} */
	#property;

	/** @param {any} p */
	constructor(p) {
		super();
		this.#property = p;
	}

	get prop() {
		return this.#property;
	}
}
```

## Problem
When running `deno lint a.js b.js`, `Program::comments` only points to `a.js` comments even though getting the comments through `Contex::sourceCode` object works as expected.

```js
Context {
