denoland/deno#32006.body:
Version: Deno 2.6.7

PR #31932 fixed the socket hang up error from #31891 by adding retry logic for stale keepalive connections. However, when the retry triggers on a POST/PUT request, the request body is not re-sent, causing the request to hang.

```typescript
 import http from "node:http";

 const PORT = 19876;

 async function runServer(): Promise<Deno.Listener> {
   const listener = Deno.listen({ port: PORT });
   (async () => {
     for await (const conn of listener) {
       handleConnection(conn);
     }
   })();
   return listener;
 }

 async function handleConnection(conn: Deno.Conn) {
   const buf = new Uint8Array(4096);
   let request = "";
   while (true) {
     const n = await conn.read(buf);
     if (n === null) return;
     request += new TextDecoder().decode(buf.subarray(0, n));
     const headerEnd = request.indexOf("\r\n\r\n");
     if (headerEnd !== -1 && request.length >= headerEnd + 4 + 13) break;
   }
   const body = '{"ok":true}';
   const response = `HTTP/1.1 200 OK\r\nContent-Length: ${body.length}\r\nConnection:
 keep-alive\r\n\r\n${body}`;
   await conn.write(new TextEncoder().encode(response));
   setTimeout(() => conn.close(), 50);
 }

 function postRequest(agent: http.Agent): Promise<string> {
   return new Promise((resolve, reject) => {
     const timeout = setTimeout(() => reject(new Error("timeout")), 5000);
     const req = http.request(
       { hostname: "127.0.0.1", port: PORT, method: "POST", agent, headers: {
 "Content-Length": "13" } },
       (res) => {
         let data = "";
         res.on("data", (c) => (data += c));
         res.on("end", () => { clearTimeout(timeout); resolve(data); });
       },
     );
     req.on("error", (e) => { clearTimeout(timeout); reject(e); });
     req.write('{"test":true}');
     req.end();
   });
 }

 async function main() {
   console.log(`Deno ${Deno.version.deno}`);
   const listener = await runServer();
   const agent = new http.Agent({ keepAlive: true });

   try {
     await postRequest(agent);
     console.log("Request 1: OK");
     await new Promise((r) => setTimeout(r, 100));
     await postRequest(agent);
     console.log("Request 2: OK");
     console.log("PASS");
   } catch (e) {
     console.log(`FAIL: ${e}`);
   } finally {
     agent.destroy();
     listener.close();
   }
 }

 main();
```

$ deno run --allow-net repro.ts

Results:
  - 2.6.3: PASS
  - 2.6.4: FAIL: Error: socket hang up
  - 2.6.7: FAIL: Error: timeout

On 2.6.7, the retry opens a new connection but never sends the request body. The server waits for a body that never arrives.

This causes intermittent failures with Google Cloud client libraries (@google-cloud/tasks, etc.) using google-gax REST transport. Servers return 408 Request Timeout because they receive headers but no body.

Workaround: downgrade to 2.6.3.

