Hi,

I would like to report a behavior I observed in Deno while running the following snippet:

#### PoC

```javascript
const asyncHooks = require('async_hooks');
const http = require('http');
const finished = require('stream').finished;

const asyncLocalStorage = new asyncHooks.AsyncLocalStorage();
const store = { foo: 'bar' };

const server = http.createServer(function (req, res) {
  asyncLocalStorage.run(store, function () {
    finished(res, function () {
      const value = asyncLocalStorage.getStore()?.foo;
      console.log('value inside finished callback:', value);
      if (value !== 'bar') {
        console.error('BUG: expected "bar" but got', value);
      } else {
        console.log('OK: got expected value');
      }
    });
  });

  setTimeout(res.end.bind(res), 0);
}).listen(0, function () {
  const port = this.address().port;
  http.get('http://127.0.0.1:' + port, function onResponse(res) {
    res.resume();
    res.on('end', server.close.bind(server));
  });
});
```

#### Expected Behavior:
In Node.js, the context is correctly propagated, and `asyncLocalStorage.getStore()` returns the expected value inside the finished callback.
```
